import{c as n,S as t,j as h,m as i}from"./chunks/framework.8aa1YH_s.js";const u=JSON.parse('{"title":"Dashboard - Trang tổng quan (Giáo viên)","description":"","frontmatter":{},"headers":[],"relativePath":"giao-vien/dashboard.md","filePath":"giao-vien/dashboard.md","lastUpdated":0}'),r={name:"giao-vien/dashboard.md"};function o(d,a,s,l,e,g){return t(),h("div",null,[...a[0]||(a[0]=[i('<h1 id="dashboard-trang-tong-quan-giao-vien" tabindex="-1">Dashboard - Trang tổng quan (Giáo viên) <a class="header-anchor" href="#dashboard-trang-tong-quan-giao-vien" aria-label="Permalink to “Dashboard - Trang tổng quan (Giáo viên)”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/teacher/dashboard</code></p><p>Trang đầu tiên hiển thị khi bạn đăng nhập tài khoản giáo viên.</p><h2 id="cac-the-so-lieu" tabindex="-1">Các thẻ số liệu <a class="header-anchor" href="#cac-the-so-lieu" aria-label="Permalink to “Các thẻ số liệu”">​</a></h2><table tabindex="0"><thead><tr><th>Thẻ</th><th>Ý nghĩa</th></tr></thead><tbody><tr><td><strong>Tổng số khóa học</strong></td><td>Số khóa do bạn phụ trách</td></tr><tr><td><strong>Tổng số học viên</strong></td><td>Học viên đang học các khóa của bạn</td></tr><tr><td><strong>Tổng số đề thi</strong></td><td>Số đề thi bạn đã tạo</td></tr><tr><td><strong>Tổng số bài giảng</strong></td><td>Tổng bài giảng đã đăng</td></tr><tr><td><strong>Câu hỏi chờ trả lời</strong></td><td>Số lượng câu hỏi học viên đang chờ</td></tr></tbody></table><p>Bấm vào thẻ để mở danh sách chi tiết.</p><h2 id="bieu-đo-danh-sach-nhanh" tabindex="-1">Biểu đồ &amp; danh sách nhanh <a class="header-anchor" href="#bieu-đo-danh-sach-nhanh" aria-label="Permalink to “Biểu đồ &amp; danh sách nhanh”">​</a></h2><ul><li><strong>Học viên mới</strong> trong các khóa của bạn (7-30 ngày qua).</li><li><strong>Điểm trung bình</strong> từng đề thi gần đây.</li><li><strong>Top học viên</strong> điểm cao của tuần / tháng.</li><li><strong>Câu hỏi mới</strong> chưa trả lời (link sang <a href="./hoi-dap">Hỏi đáp</a>).</li></ul><h2 id="lich-trinh-sap-toi" tabindex="-1">Lịch trình sắp tới <a class="header-anchor" href="#lich-trinh-sap-toi" aria-label="Permalink to “Lịch trình sắp tới”">​</a></h2><ul><li><strong>Lớp học sắp diễn ra</strong> (nếu lớp có lịch live).</li><li><strong>Đợt thi thử</strong> đã lên lịch.</li><li><strong>Khóa sắp đóng đăng ký</strong>.</li></ul><h2 id="goi-y-dung-dashboard" tabindex="-1">Gợi ý dùng Dashboard <a class="header-anchor" href="#goi-y-dung-dashboard" aria-label="Permalink to “Gợi ý dùng Dashboard”">​</a></h2><ol><li>Vào trang Dashboard mỗi sáng.</li><li>Ưu tiên trả lời <strong>Câu hỏi chờ</strong> trước (mỗi câu hỏi tồn lâu là một học viên không học được).</li><li>Nếu điểm trung bình đề thi quá thấp → mở <a href="./quan-ly-diem-thi">Quản lý điểm thi</a> phân tích nguyên nhân (đề khó hay học viên chưa học?).</li><li>Cuối tuần kiểm tra biểu đồ học viên mới để đánh giá hiệu quả khóa.</li></ol><h2 id="khi-dashboard-khong-cap-nhat" tabindex="-1">Khi dashboard không cập nhật <a class="header-anchor" href="#khi-dashboard-khong-cap-nhat" aria-label="Permalink to “Khi dashboard không cập nhật”">​</a></h2><ul><li>Bấm nút <strong>Làm mới</strong> (refresh).</li><li>Nếu vẫn sai, đăng xuất / đăng nhập lại.</li><li>Nếu vẫn lỗi, báo Admin.</li></ul>',14)])])}const b=n(r,[["render",o]]);export{u as __pageData,b as default};
